INSERT INTO `feedback` (`feedback_id`, `feedback_type`, `module_name`, `rating`, `comments`, `suggestion`, `attachment_path`, `contact_required`, `status`, `created_at`, `updated_at`, `create_by`, `updated_by`) VALUES
(1, 'Appreciation', 'General', 5, 'User-friendly Application ', '', NULL, 'N', 'Open', '2026-02-12 05:50:52', '2026-02-12 05:50:52', 1, 1),
(2, 'Suggestion', 'Approval', 0, 'Provision of exit apply option at requester and pending application is shown to HRMS package', 'Our department is responsible for vehicle servicing and related maintenance works. Sometimes, visitors such as mechanics, helpers, and other maintenance personnel come only for repair and service purposes. As per the maintenance requirements, such visitors may not need to meet the approval authority. Therefore, after completion of the work and necessary compliance, an exit button option should be provided for the pass requester to close the request. Currently, the status remains pending in the existing HRMS package flow chart.', NULL, 'N', 'Closed', '2026-02-12 09:46:39', '2026-02-18 06:26:40', 85, 1),
(3, 'Suggestion', 'Visitor Request', 4, 'For some final quotations, the Central Purchase Department conducts rate negotiations with the vendor through face-to-face discussions.', 'One of additional selection field of \"Rate negotiations\"  is required  ', NULL, 'N', 'Closed', '2026-02-18 05:19:27', '2026-02-19 10:04:23', 85, 1);
